/* ===== menu ===== */

/**
 * Marbl Codes — Fullscreen Menu (v2)
 * 40/60 split with 60-tick SVG clock
 */

class MarblMenu {
  constructor() {
    this.overlay = document.querySelector('.menu-overlay');
    this.toggle = document.querySelector('.menu-toggle');
    this.panelBack = document.querySelector('.menu-overlay__panel--back');
    this.panelFront = document.querySelector('.menu-overlay__panel--front');
    this.content = document.querySelector('.menu-overlay__content');
    this.navItems = document.querySelectorAll('.menu-overlay__nav-item a');
    this.centre = document.querySelector('.menu-overlay__centre');
    this.right = document.querySelector('.menu-overlay__right');
    this.sections = document.querySelectorAll('.menu-overlay__section');

    this.isOpen = false;
    this.isAnimating = false;
    this.timeline = null;
    this.clockRAF = null;

    if (!this.overlay || !this.toggle) return;

    this._buildClock();
    this._splitText();
    this._buildTimeline();
    this._bindEvents();
  }

  /* ── Clock: 60 ticks ── */

  _buildClock() {
    const svg = document.querySelector('[data-clock-svg]');
    if (!svg) return;

    const cx = 100, cy = 100, r = 88;

    for (let i = 0; i < 60; i++) {
      const angle = (i * 6 - 90) * (Math.PI / 180);
      const outer = r;
      const inner = i % 5 === 0 ? r - 14 : r - 8;

      const x1 = cx + outer * Math.cos(angle);
      const y1 = cy + outer * Math.sin(angle);
      const x2 = cx + inner * Math.cos(angle);
      const y2 = cy + inner * Math.sin(angle);

      const line = document.createElementNS('http://www.w3.org/2000/svg', 'line');
      line.setAttribute('x1', x1);
      line.setAttribute('y1', y1);
      line.setAttribute('x2', x2);
      line.setAttribute('y2', y2);
      line.setAttribute('class', 'menu-clock__tick');
      line.setAttribute('data-tick', i);
      svg.appendChild(line);
    }

    this.ticks = svg.querySelectorAll('.menu-clock__tick');
    this.digitalDisplay = document.querySelector('[data-clock-digital]');
  }

  _startClock() {
    const tick = () => {
      const now = new Date();
      const londonStr = now.toLocaleString('en-GB', { timeZone: 'Europe/London', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false });
      const parts = londonStr.split(':');
      const h = parseInt(parts[0]);
      const m = parseInt(parts[1]);
      const s = parseInt(parts[2]);

      // Light up ticks 0 through current second
      if (this.ticks) {
        this.ticks.forEach((tick, i) => {
          if (i <= s) {
            tick.classList.add('menu-clock__tick--active');
          } else {
            tick.classList.remove('menu-clock__tick--active');
          }
        });
      }

      // Digital time
      if (this.digitalDisplay) {
        this.digitalDisplay.textContent = `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
      }

      this.clockRAF = requestAnimationFrame(tick);
    };

    tick();
  }

  _stopClock() {
    if (this.clockRAF) {
      cancelAnimationFrame(this.clockRAF);
      this.clockRAF = null;
    }
    // Reset all ticks
    if (this.ticks) {
      this.ticks.forEach(t => t.classList.remove('menu-clock__tick--active'));
    }
  }

  /* ── Text split ── */

  _splitText() {
    this.navItems.forEach(item => {
      if (typeof SplitText !== 'undefined') {
        new SplitText(item, { type: 'chars', charsClass: 'char' });
      } else {
        const text = item.textContent;
        item.innerHTML = '';
        text.split('').forEach(char => {
          const span = document.createElement('span');
          span.classList.add('char');
          span.textContent = char === ' ' ? '\u00A0' : char;
          item.appendChild(span);
        });
      }
    });
    this.allChars = this.overlay.querySelectorAll('.char');
  }

  /* ── GSAP timeline ── */

  _buildTimeline() {
    this.timeline = gsap.timeline({
      paused: true,
      defaults: { ease: 'power4.inOut' },
      onReverseComplete: () => {
        this.overlay.classList.remove('is-open');
        document.body.style.overflow = '';
        this.isAnimating = false;
      }
    });

    this.timeline
      .to(this.panelBack, { clipPath: 'inset(0 0 0% 0)', duration: 0.8 })
      .to(this.panelFront, { clipPath: 'inset(0 0 0% 0)', duration: 0.8 }, '-=0.6')
      .to(this.content, { opacity: 1, duration: 0.3, ease: 'power2.out' }, '-=0.3')
      .fromTo(this.allChars, { opacity: 0, y: '100%' }, {
        opacity: 1, y: '0%', duration: 0.6, stagger: 0.02, ease: 'power3.out'
      }, '-=0.2');

    // Clock fades in
    if (this.centre) {
      this.timeline.fromTo(this.centre, { opacity: 0, scale: 0.95 }, {
        opacity: 1, scale: 1, duration: 0.6, ease: 'power2.out'
      }, '-=0.3');
    }

    // Right sections stagger in
    if (this.sections.length) {
      this.timeline.fromTo(this.sections, { opacity: 0, y: 20 }, {
        opacity: 1, y: 0, duration: 0.5, stagger: 0.1, ease: 'power2.out'
      }, '-=0.4');
    }
  }

  /* ── Events ── */

  _bindEvents() {
    this.toggle.addEventListener('click', () => this._toggle());
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && this.isOpen) this._close();
    });
    this.navItems.forEach(item => {
      item.addEventListener('click', () => { if (this.isOpen) this._close(); });
    });
  }

  _toggle() {
    if (this.isAnimating) return;
    this.isOpen ? this._close() : this._open();
  }

  _open() {
    if (this.isAnimating || this.isOpen) return;
    this.isAnimating = true;
    this.isOpen = true;

    this.overlay.classList.add('is-open');
    this.toggle.classList.add('is-open');
    document.body.style.overflow = 'hidden';
    if (window.innerWidth <= 768) {
      document.querySelector('.site-header')?.classList.add('menu-is-open');
    }
    this._startClock();

    this.timeline.timeScale(1).play().then(() => { this.isAnimating = false; });
  }

  _close() {
    if (this.isAnimating || !this.isOpen) return;
    this.isAnimating = true;
    this.isOpen = false;

    this.toggle.classList.remove('is-open');
    document.querySelector('.site-header')?.classList.remove('menu-is-open');
    this._stopClock();

    this.timeline.timeScale(1.5).reverse();
  }
}

document.addEventListener('DOMContentLoaded', () => {
  if (typeof gsap !== 'undefined') {
    new MarblMenu();
  }
});


/* ===== hero ===== */

/**
 * Marbl Codes — Hero: Water Shader on Marble Man
 *
 * Three.js renders the marble man texture on a fullscreen plane.
 * Post-processing shader distorts the image with water ripples
 * that follow cursor movement (Theia technique).
 * Subtle parallax on cursor position.
 *
 * Dependencies: Three.js
 */

class MarblHero {
  constructor() {
    this.container = document.querySelector('.hero__canvas');
    if (!this.container || typeof THREE === 'undefined') return;

    this.width = window.innerWidth;
    this.height = window.innerHeight;
    this.mouse = { x: 0.5, y: 0.5 };
    this.smoothMouse = { x: 0.5, y: 0.5 };
    this.prevDrop = { x: 0.5, y: 0.5 };
    this.clock = new THREE.Clock();

    // Water ripples — continuous from cursor movement
    this.MAX_RIPPLES = 20;
    this.RIPPLE_LIFETIME = 3.0;
    this.ripples = [];

    this._init();
    this._loadTexture();
  }

  _init() {
    this.scene = new THREE.Scene();
    this.camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);

    this.renderer = new THREE.WebGLRenderer({ antialias: false, alpha: false });
    this.renderer.setSize(this.width, this.height);
    this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    this.renderer.setClearColor(0x0d0c0c, 1);
    this.container.appendChild(this.renderer.domElement);

    this._bindEvents();
  }

  _loadTexture() {
    new THREE.TextureLoader().load('/assets/images/characters/marbl-man-tall.webp', (texture) => {
      texture.minFilter = THREE.LinearFilter;
      texture.magFilter = THREE.LinearFilter;
      this.texture = texture;
      this._createScene();
      this._animate();
      console.log('[Hero] Water shader hero initialised');
    });
  }

  _createScene() {
    const imgAspect = this.texture.image.width / this.texture.image.height;
    const screenAspect = this.width / this.height;

    // Build ripple uniform arrays
    const ripplePos = [];
    const rippleAge = new Float32Array(this.MAX_RIPPLES);
    for (let i = 0; i < this.MAX_RIPPLES; i++) {
      ripplePos.push(new THREE.Vector2(-10, -10));
      rippleAge[i] = 1.0;
    }

    this.uniforms = {
      uTexture: { value: this.texture },
      uTime: { value: 0 },
      uMouse: { value: new THREE.Vector2(0.5, 0.5) },
      uResolution: { value: new THREE.Vector2(this.width, this.height) },
      uImageAspect: { value: imgAspect },
      uScreenAspect: { value: screenAspect },
      uWaterStrength: { value: 0.006 },
      uRipplePos: { value: ripplePos },
      uRippleAge: { value: rippleAge },
      uGrain: { value: 0.03 }
    };

    const vertexShader = `
      varying vec2 vUv;
      void main() {
        vUv = uv;
        gl_Position = vec4(position, 1.0);
      }
    `;

    const fragmentShader = `
      uniform sampler2D uTexture;
      uniform float uTime;
      uniform vec2 uMouse;
      uniform vec2 uResolution;
      uniform float uImageAspect;
      uniform float uScreenAspect;
      uniform float uWaterStrength;
      uniform float uGrain;
      uniform vec2 uRipplePos[${this.MAX_RIPPLES}];
      uniform float uRippleAge[${this.MAX_RIPPLES}];

      varying vec2 vUv;

      float hash(vec2 p) {
        return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
      }

      void main() {
        // Cover-fit image to viewport
        vec2 uv = vUv;
        if (uScreenAspect > uImageAspect) {
          float scale = uScreenAspect / uImageAspect;
          uv.y = uv.y / scale + (1.0 - 1.0 / scale) * 0.5;
        } else {
          float scale = uImageAspect / uScreenAspect;
          uv.x = uv.x / scale + (1.0 - 1.0 / scale) * 0.5;
        }

        // Subtle parallax — image shifts with cursor
        uv += (uMouse - 0.5) * 0.015;

        // Water ripple distortion
        vec2 waterOffset = vec2(0.0);
        for (int i = 0; i < ${this.MAX_RIPPLES}; i++) {
          float age = uRippleAge[i];
          if (age >= 1.0) continue;

          float dist = distance(vUv, uRipplePos[i]);
          float rad = age * 0.5;
          float ring = exp(-pow((dist - rad) * 30.0, 2.0));
          float fade = pow(1.0 - age, 1.5);
          float wave = sin(dist * 50.0 - age * 25.0) * ring * fade;

          vec2 dir = (dist > 0.001) ? normalize(vUv - uRipplePos[i]) : vec2(0.0);
          waterOffset += dir * wave;
        }
        uv += waterOffset * uWaterStrength;

        // Sample texture
        vec4 color = texture2D(uTexture, uv);

        // Background where image is transparent
        vec3 bg = vec3(0.051, 0.047, 0.047);
        vec3 final = mix(bg, color.rgb, color.a);

        // Subtle film grain
        final += (hash(vUv * uResolution + fract(uTime * 100.0)) - 0.5) * uGrain;

        gl_FragColor = vec4(final, 1.0);
      }
    `;

    const geometry = new THREE.PlaneGeometry(2, 2);
    this.material = new THREE.ShaderMaterial({
      uniforms: this.uniforms,
      vertexShader,
      fragmentShader
    });

    this.scene.add(new THREE.Mesh(geometry, this.material));
  }

  _addRipple(x, y) {
    const rx = x / this.width;
    const ry = 1 - y / this.height;
    const time = this.clock.getElapsedTime();

    this.ripples.push({ x: rx, y: ry, birth: time });

    if (this.ripples.length > this.MAX_RIPPLES) {
      this.ripples.shift();
    }
  }

  _bindEvents() {
    window.addEventListener('mousemove', (e) => {
      this.mouse.x = e.clientX / this.width;
      this.mouse.y = 1 - e.clientY / this.height;

      // Drop ripples as cursor moves (like dragging through water)
      const dx = this.mouse.x - this.prevDrop.x;
      const dy = this.mouse.y - this.prevDrop.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist > 0.02) {
        this._addRipple(e.clientX, e.clientY);
        this.prevDrop.x = this.mouse.x;
        this.prevDrop.y = this.mouse.y;
      }
    });

    // Click adds a stronger burst of ripples
    window.addEventListener('mousedown', (e) => {
      const time = this.clock.getElapsedTime();
      const rx = e.clientX / this.width;
      const ry = 1 - e.clientY / this.height;
      this.ripples.push(
        { x: rx, y: ry, birth: time },
        { x: rx + 0.01, y: ry + 0.01, birth: time + 0.03 },
        { x: rx - 0.01, y: ry - 0.008, birth: time + 0.06 }
      );
      if (this.ripples.length > this.MAX_RIPPLES) {
        this.ripples.splice(0, this.ripples.length - this.MAX_RIPPLES);
      }
    });

    window.addEventListener('touchmove', (e) => {
      const tx = e.touches[0].clientX;
      const ty = e.touches[0].clientY;
      this.mouse.x = tx / this.width;
      this.mouse.y = 1 - ty / this.height;

      const dx = this.mouse.x - this.prevDrop.x;
      const dy = this.mouse.y - this.prevDrop.y;
      if (Math.sqrt(dx * dx + dy * dy) > 0.02) {
        this._addRipple(tx, ty);
        this.prevDrop.x = this.mouse.x;
        this.prevDrop.y = this.mouse.y;
      }
    }, { passive: true });

    window.addEventListener('resize', () => this._onResize());
  }

  _onResize() {
    this.width = window.innerWidth;
    this.height = window.innerHeight;
    this.renderer.setSize(this.width, this.height);

    if (this.uniforms) {
      this.uniforms.uResolution.value.set(this.width, this.height);
      this.uniforms.uScreenAspect.value = this.width / this.height;
    }
  }

  _updateRipples() {
    if (!this.uniforms) return;

    const time = this.clock.getElapsedTime();
    const positions = this.uniforms.uRipplePos.value;
    const ages = this.uniforms.uRippleAge.value;

    for (let i = 0; i < this.MAX_RIPPLES; i++) {
      if (i < this.ripples.length) {
        const r = this.ripples[i];
        positions[i].set(r.x, r.y);
        ages[i] = Math.min((time - r.birth) / this.RIPPLE_LIFETIME, 1.0);
      } else {
        ages[i] = 1.0;
      }
    }

    this.ripples = this.ripples.filter(r => (time - r.birth) / this.RIPPLE_LIFETIME < 1.0);
  }

  _animate() {
    requestAnimationFrame(() => this._animate());

    if (!this.uniforms) return;

    this.uniforms.uTime.value = this.clock.getElapsedTime();

    // Smooth mouse follow
    this.smoothMouse.x += (this.mouse.x - this.smoothMouse.x) * 0.05;
    this.smoothMouse.y += (this.mouse.y - this.smoothMouse.y) * 0.05;
    this.uniforms.uMouse.value.set(this.smoothMouse.x, this.smoothMouse.y);

    this._updateRipples();
    this.renderer.render(this.scene, this.camera);
  }
}

document.addEventListener('DOMContentLoaded', () => {
  if (typeof THREE !== 'undefined') {
    try {
      new MarblHero();
    } catch (e) {
      console.error('[Hero] Init failed:', e);
    }
  }
});


